from checkers_game import CheckersGame
import argparse
import colorama

def prompt_move(player):
    return input(f"Player {player.color}, enter your move (e.g., A1-B2): ")

def validate_and_execute_move(game, move):
    if game.is_valid_move(move):
        game.execute_move(move)
        return True
    else:
        print("Invalid move. Try again.")
        return False

if __name__ == "__main__":
    colorama.init()

    parser = argparse.ArgumentParser(description="Play Checkers")
    args = parser.parse_args()

    game = CheckersGame()
    game.initialize_board()

    current_player = game.player1
    while not game.is_game_over():
        print(game.board)
        move = prompt_move(current_player)
        if validate_and_execute_move(game, move):
            game.switch_turns()

    print(f"Game Over! {game.winner} wins.")
